var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"공군 기술 연구소 임시 선착장\\n델타 세븐 기함, 엔터프라이즈 <color=#ffd34c>개장 작업 중</color>\\nCSE Lv. <b>0</b>","JPN":"空軍技術研究所の臨時船着き場\\nデルタセブンの旗艦、エンタープライズの<color=#ffd34c>改装作業中</color>\\nCSE Lv. <b>0</b>","ENG":"[[","TWN":"空軍技術研究所臨時機庫\\n第七三角洲部隊艦船 企業號 <color=#ffd34c>改裝作業中</color>\\nCSE Lv. <b>0</b>","THA":"ลานจอดชั่วคราวห้องวิจัยกองทัพอากาศ\\nเอ็นเตอร์ไพรส์ ยานรบหลักของเดลต้าเซเว่น<color=#ffd34c>อยู่ระหว่างการดัดแปลง</color>\\nCSE เลเวล <b>0</b>","VTN":"Căn Cứ Tạm Thời Phòng Nghiên Cứu Lực Lượng Không Quân, \\nTàu Đô Đốc Delta Seven, Enterprise <color=#ffd34c>đang được tu sửa</color>\\nCấp CSE<b> 0 </b>","SCN":"空军研究所临时船坞\\n德尔塔部队旗舰，企业号<color=#ffd34c>改装工作进行中</color>\\nCSE Lv. <b>0</b>","DEU":"Temporäres Dock des Technischen Forschungsinstituts der Luftwaffe\\nDelta Seven Flaggschiff, Enterprise, <color=#ffd34c>wird umgestaltet</color>\\nCSE-St.: <b>0</b>","FRA":"Laboratoire de recherche de l'Armée de l'Air, Passerelle temporaire\\nVaisseau amiral du Delta Seven Enterprise <color=#ffd34c>Rénovation en cours</color>\\nNiveau d'ECM : <b>0</b>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"매버릭, 그쪽 일은 어때?","JPN":"マーベリック、そっちはどう？","ENG":"How are things going Maverick?","TWN":"麥伯利，你那邊如何？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"말도 마. 엔진 갈아치우면 에이허브에 탑재된 기상 조절 시스템도 뜯어 놓으란다.","JPN":"最悪。エンジンを替えた後にはエイハブに搭載されてる天候調節システムも外しておけって。","ENG":"Don’t get me started. They said that once we’re done replacing the engine, we have to dismantle the weather control system attached to the Ahab.","TWN":"別說了，換掉引擎的話，原本搭載在亞哈上的氣象調節系統也要拆掉。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그것도 열─두─ 시간 안에.","JPN":"それも十～二～時間内に。","ENG":"And they want this done in TWELVE. HOURS.","TWN":"而且還必須在12個小時內完成！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"역시 군인 놈들은 제정신이 아니야. 오늘 안에 방 정리 다 하라는 우리 엄마보다 더 심해.","JPN":"やっぱ軍人の奴らは正気じゃない。今日中に部屋の掃除を終わらせろっていうお母さんよりひどいんだ。","ENG":"I knew it, these military guys are nuts. They’re worse than my mom when she tells me to clean my room within today.","TWN":"軍人果然腦袋都不太正常，我媽頂多叫我今天之內把房間整理好，他們比我媽還超過！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"에잇! 이럴 줄 알았으면 차라리 편안한 수용소 안에 있는 건데!","JPN":"えいっ！　こうなるとわかってたら、いっそ楽な収容所に残っていればよかった！","ENG":"Damn it! If I knew it would be like this, I would’ve just stayed comfortably in prison!","TWN":"嘖！早知如此，還不如乾脆就待在收容所裡！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"거기선 몸이라도 편했다고! 밥도 맛있었고!","JPN":"あそこは少なくとも体は楽だったんだよ！　ご飯も美味しかったし！","ENG":"At least it was comfortable there! And the food was good!","TWN":"在所裡多舒適！連飯都比較好吃！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"군대 밥이 수용소 보다 더 맛없다니 이게 말이 돼?!","JPN":"軍隊のご飯が収容所よりまずいなんてあり得ないでしょう！？","ENG":"How can military food be more disgusting than prison food?!","TWN":"軍隊的伙食竟然比收容所的還差！這說得過去嗎？！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"욕망에 굴복해선 안돼, 친구!","JPN":"欲望に負けるな、友よ！","ENG":"You must not give in to your urges, comrade!","TWN":"朋友，不能屈服於口腹之慾！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"우린 어둠 속에서 자유를 위해 투쟁하는 하나이자 일곱! 일곱이자 하나!","JPN":"私たちは闇の中で自由のために戦う一人で七人！　七人で一人！","ENG":"We fight for freedom within the darkness! Seven for one! One for seven!","TWN":"我們可是在黑暗中為自由而奮鬥的一群人，我們是七！是七也是一！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"다-크 세븐이라고.","JPN":"ダーークセブンなんだよ。","ENG":"We are Daark Seven.","TWN":"我們是Dark 7！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"분명 넘버 1이 우릴 구하러 올 거야!","JPN":"きっとナンバー1が私たちを助けに来てくれる！","ENG":"Surely Number 1 will come save us!","TWN":"1號一定會來救我們的！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그, 그래, 넘버 1이라면 분명 우리가 이대로 고통 받게 내버려 둘 리 없어!","JPN":"そ、そう、ナンバー1ならきっと私たちが苦しんでるところを見捨てないはずだ！","ENG":"Th-that's right! Knowing Number 1, there’s no way that he’ll leave us suffering like this!","TWN":"嗯…你說的沒錯，1號不會讓我們就這樣一直受苦的！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그리고…… 좀 미덥진 않지만 넘버2도 있고…….","JPN":"あと……ちょっと頼りないけどナンバー2もいるし……","ENG":"Also... Although not very trustworthy, there’s also Number 2...","TWN":"況且……還有不太靠譜2號……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"저, 정말? 넘버2가 우릴 도와줄까?","JPN":"ほ、本当？　ナンバー2が私たちを助けてくれるかな？","ENG":"R-really? But will Number 2 help us?","TWN":"真…真的嗎？2號會幫我們嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"솔직히 말하면…… 아니.","JPN":"正直に言うと……望み薄。","ENG":"To be honest... I don’t think so.","TWN":"說實話嗎……不會。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"……크흥! 사실 내 생각도 그래.","JPN":"……チーン！　実は私もそう思う。","ENG":"...Ahem! Honestly, I also don’t think so either.","TWN":"……咳咳！其實我也覺得不會。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};